function showDetail(key) {
  const d = SALES_DATA.find(x => x.lecture_key === key);
  if (!d) return;
  currentDetailKey = key;
  selectedKey = key;
  document.getElementById('global-filter').value = key;
  const kisuStr = (d.기수List||[]).filter(k=>k!=='-').join(', ');
  document.getElementById('detail-name').textContent = d.강의그룹명;
  document.getElementById('detail-meta').innerHTML =
    '<span>강사: '+d.강사+'</span>' +
    '<span>플랫폼: '+d.플랫폼+'</span>' +
    (kisuStr ? '<span>기수: '+kisuStr+'</span>' : '') +
    '<span>총 '+d.rows.length+'개 데이터</span>';

  // KPI
  document.getElementById('kpi-total').innerHTML = fmtUnit(d.강의총매출,'원');
  document.getElementById('kpi-students').innerHTML = fmtUnit(d.수강생수,'명');
  document.getElementById('kpi-free').innerHTML = fmtUnit(d.무료강의신청수,'명');
  const cvr = d.무료강의신청수 > 0 ? (d.수강생수/d.무료강의신청수*100) : 0;
  document.getElementById('kpi-cvr').innerHTML =
    '<span style="font-size:28px;font-weight:800;letter-spacing:-.02em;">'+cvr.toFixed(2)+'</span><span class="kpi-unit">%</span>';
  document.getElementById('kpi-cvr-sub').textContent = '신청 '+d.무료강의신청수.toLocaleString()+'명 → 결제 '+d.수강생수+'명';
  // 영업이익
  document.getElementById('kpi-net').innerHTML = '<span style="font-size:22px;font-weight:800;">'+fmt(d.순매출)+'</span><span style="font-size:12px;color:var(--muted);margin-left:2px;">원</span>';
  const margin = d.강의총매출 > 0 ? (d.순매출/d.강의총매출*100) : 0;
  document.getElementById('kpi-margin').innerHTML = margin.toFixed(2)+'<span>%</span>';
  document.getElementById('profit-bar').style.width = Math.min(Math.max(margin,0),100)+'%';
  document.getElementById('profit-bar-label').textContent = '이익 '+margin.toFixed(2)+'%';
  // 광고
  const roas = d.광고비 > 0 ? (d.강의총매출/d.광고비) : 0;
  document.getElementById('kpi-roas').textContent = roas > 0 ? roas.toFixed(1) : '-';
  document.getElementById('kpi-roas-sub').textContent = roas > 0 ? '광고비 대비 매출' : '광고비 없음';
  document.getElementById('kpi-adcost').innerHTML = d.광고비 > 0
    ? '<span style="font-size:20px;font-weight:800;color:#f472b6;">'+fmt(d.광고비)+'</span><span style="font-size:12px;color:var(--muted);margin-left:2px;">원</span>'
    : '<span style="font-size:16px;font-weight:600;color:var(--muted);">-</span>';
  document.getElementById('kpi-teacher').innerHTML =
    '<span style="font-size:20px;font-weight:800;color:var(--accent2);">'+fmt(d.강사정산금)+'</span><span style="font-size:12px;color:var(--muted);margin-left:2px;">원</span>';

  renderCharts(d);
  renderKisuTable(d.rows);
  renderTimeChart(key);
  showPage('detail');
}

