//  시간별 구매 추이 차트
// ════════════════════════════════════════════════════
function reRenderTimeChart() { renderTimeChart(currentDetailKey); }

// 강의 무료강의일 기준 19:30~익일 06:00 윈도우 외 주문 제거
function filterByLectureDates(ordersArr, lecData) {
  if (!lecData || !lecData.rows || lecData.rows.length === 0) return ordersArr;
  const daySet = new Set();
  lecData.rows.forEach(r => {
    if (!r.무료강의일) return;
    const s = String(r.무료강의일).replace(/\./g,'-').replace(/\//g,'-').trim();
    const p = s.split('-');
    if (p.length >= 3) daySet.add(p[0] + '-' + parseInt(p[1]) + '-' + parseInt(p[2]));
  });
  if (daySet.size === 0) return ordersArr;
  return ordersArr.filter(o => {
    const absMin = o.ts.getHours() * 60 + o.ts.getMinutes();
    const checkDate = new Date(o.ts);
    // 자정~06:00 주문은 전날 강의에 속함
    if (absMin < 6 * 60) checkDate.setDate(checkDate.getDate() - 1);
    const key = checkDate.getFullYear() + '-' + (checkDate.getMonth()+1) + '-' + checkDate.getDate();
    return daySet.has(key);
  });
}

function renderTimeChart(key) {
  const intervalMin = parseInt(document.getElementById('interval-select').value) || 10;
  const sub = document.getElementById('time-chart-sub');

  // 해당 강의 주문 필터
  let orders = ORDER_DATA;
  let matchMode = 'all'; // 'matched' | 'fallback' | 'all'

  if (key && ORDER_DATA.length > 0) {
    const d = SALES_DATA.find(x => x.lecture_key === key);
    if (d) {
      const normGroup = d.강의그룹명.toLowerCase().replace(/\s+/g,' ').trim();
      const matched = ORDER_DATA.filter(o => {
        const normOrder = normalizeLectureName(o.lectureName).toLowerCase().replace(/\s+/g,' ').trim();
        return normOrder === normGroup
          || normOrder.includes(normGroup)
          || normGroup.includes(normOrder)
          || (normGroup.length >= 8 && normOrder.startsWith(normGroup.slice(0, Math.min(normGroup.length, 12))));
      });
      if (matched.length > 0) {
        orders = matched;
        matchMode = 'matched';
      } else {
        // 매칭 실패 → 전체 주문으로 폴백, 안내 표시
        orders = ORDER_DATA;
        matchMode = 'fallback';
        console.warn('[시간차트] 강의 매칭 실패. 검색어:', normGroup,
          '| 주문 데이터 샘플:', ORDER_DATA.slice(0,3).map(o=>o.lectureName));
      }
    }
  }

  if (orders.length === 0) {
    sub.textContent = '주문 결제 데이터를 업로드하면 표시됩니다';
    if (charts.time) { charts.time.destroy(); charts.time = null; }
    renderOrderList([]);
    return;
  }

  // 강의 당일 필터 (19:30 ~ 익일 03:00)
  const lecDayOnly = document.getElementById('lecture-day-filter').checked;
  if (lecDayOnly) {
    const lecData = SALES_DATA.find(x => x.lecture_key === key);
    if (lecData && lecData.rows.length > 0) {
      // 각 기수의 무료강의일 → 윈도우 [당일 19:30, 익일 03:00] 생성
      const windows = [];
      lecData.rows.forEach(r => {
        if (!r.무료강의일) return;
        const s = String(r.무료강의일).replace(/\./g,'-').replace(/\//g,'-').trim();
        const base = new Date(s + 'T00:00:00');
        if (isNaN(base)) return;
        const start = new Date(base); start.setHours(19, 30, 0, 0);
        const end   = new Date(base); end.setDate(end.getDate() + 1); end.setHours(3, 0, 0, 0);
        windows.push({ start, end });
      });
      if (windows.length > 0) {
        orders = orders.filter(o => windows.some(w => o.ts >= w.start && o.ts <= w.end));
      }
    }
  }

  if (matchMode === 'fallback') {
    sub.textContent = '⚠️ 강의 매칭 실패 — 전체 주문 '+orders.length+'건 표시 중 (F12 콘솔에서 강의명 확인)';
    sub.style.color = 'var(--yellow)';
  } else if (matchMode === 'matched') {
    sub.textContent = (lecDayOnly ? '[당일 필터] ' : '') + '매칭 '+orders.length+'건 / '+intervalMin+'분 단위';
    sub.style.color = '';
  } else {
    sub.textContent = '전체 '+orders.length+'건 / '+intervalMin+'분 단위';
    sub.style.color = '';
  }
  updateOrderCountBadge(orders.length);

  // 날짜+시간 기반 버킷 — epoch ms를 intervalMin 단위로 내림
  const intervalMs = intervalMin * 60 * 1000;
  function bucketLabel(tsMs) {
    const d = new Date(tsMs);
    return (d.getMonth()+1) + '/' + pad2(d.getDate()) + ' ' + pad2(d.getHours()) + ':' + pad2(d.getMinutes());
  }

  const buckets = {};
  const sortedOrders = [...orders].sort((a, b) => a.ts - b.ts);
  sortedOrders.forEach(o => {
    const bk = Math.floor(o.ts.getTime() / intervalMs) * intervalMs;
    if (!buckets[bk]) buckets[bk] = { count:0, amount:0 };
    buckets[bk].count++;
    buckets[bk].amount += o.amount;
  });

  // 버킷 범위 결정
  const allBucketTs = [];
  if (sortedOrders.length > 0) {
    const lastBk = Math.floor(sortedOrders[sortedOrders.length-1].ts.getTime() / intervalMs) * intervalMs;

    let firstBk;
    if (lecDayOnly) {
      // 당일 필터: 각 기수 무료강의일 중 가장 이른 날의 19:30부터 시작
      const lecData2 = SALES_DATA.find(x => x.lecture_key === key);
      const lecDates = (lecData2 ? lecData2.rows : [])
        .map(r => String(r.무료강의일||'').replace(/\./g,'-').replace(/\//g,'-').trim())
        .filter(Boolean).sort();
      if (lecDates.length > 0) {
        const base = new Date(lecDates[0] + 'T00:00:00');
        base.setHours(19, 30, 0, 0);
        firstBk = Math.floor(base.getTime() / intervalMs) * intervalMs;
      } else {
        firstBk = Math.floor(sortedOrders[0].ts.getTime() / intervalMs) * intervalMs;
      }
    } else {
      firstBk = Math.floor(sortedOrders[0].ts.getTime() / intervalMs) * intervalMs;
    }

    for (let t = firstBk; t <= lastBk; t += intervalMs) allBucketTs.push(t);
  }
  const labels  = allBucketTs.map(t => bucketLabel(t));
  const counts  = allBucketTs.map(t => (buckets[t] ? buckets[t].count : 0));
  const amounts = allBucketTs.map(t => (buckets[t] ? buckets[t].amount : 0));
  const total   = counts.reduce((s, c) => s + c, 0) || 1;

  if (charts.time) charts.time.destroy();
  charts.time = new Chart(document.getElementById('chart-time'), {
    type: 'line',
    data: {
      labels,
      datasets: [{
        label: '구매 건수',
        data: counts,
        borderColor: '#6366f1',
        backgroundColor: 'rgba(99,102,241,0.15)',
        tension: 0.4, fill: true, pointRadius: 4, pointHoverRadius: 7,
      }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: {
        legend: { labels:{ color:'#94a3b8', font:{size:11}, boxWidth:12 } },
        tooltip: {
          callbacks: {
            title: ctx => {
              const t = allBucketTs[ctx[0].dataIndex];
              return bucketLabel(t) + ' ~ ' + bucketLabel(t + intervalMs);
            },
            label: ctx => {
              const cnt = ctx.raw;
              const pct = (cnt/total*100).toFixed(1);
              const amt = amounts[ctx.dataIndex];
              return [
                '구매 건수: ' + cnt + '건',
                '전체 대비: ' + pct + '%',
                '구간 매출: ' + fmtFull(amt) + '원'
              ];
            }
          }
        }
      },
      scales: {
        x: { ticks:{color:'#94a3b8',font:{size:10}}, grid:{color:'rgba(255,255,255,0.04)'} },
        y: { ticks:{color:'#94a3b8',font:{size:10}}, grid:{color:'rgba(255,255,255,0.04)'}, beginAtZero:true }
      }
    }
  });

  // 리스트: 전체 날짜+시간 기준 오름차순 (먼저 결제한 것 우선)
  renderOrderList([...orders].sort((a, b) => a.ts - b.ts));
}

