// localStorage에서 파일 복원 후 자동 적용
(function restoreFromStorage() {
  const b64Sales = localStorage.getItem('nova_file1');
  const b64Order = localStorage.getItem('nova_file2');
  const nameSales = localStorage.getItem('nova_name1');
  const nameOrder = localStorage.getItem('nova_name2');
  if (!b64Sales && !b64Order) return;

  const status = document.getElementById('upload-status');
  try {
    if (b64Sales) {
      pendingSales = b64ToAb(b64Sales);
      const nameEl = document.getElementById('fname1');
      const card   = document.getElementById('card1');
      nameEl.textContent = nameSales || '저장된 파일';
      nameEl.className = 'upload-card-name filled';
      card.classList.add('has-file');
    }
    if (b64Order) {
      pendingOrder = b64ToAb(b64Order);
      const nameEl = document.getElementById('fname2');
      const card   = document.getElementById('card2');
      nameEl.textContent = nameOrder || '저장된 파일';
      nameEl.className = 'upload-card-name filled';
      card.classList.add('has-file');
    }
    document.getElementById('apply-btn').disabled = false;

    // 자동 적용
    if (b64Sales) {
      const rows = parseExcelBuffer(pendingSales);
      const parsed = parseSalesRows(rows);
      SALES_DATA = aggregateByKey(parsed);
      initFilter();
    }
    if (b64Order) {
      const wb2 = XLSX.read(pendingOrder, { type: 'array', cellDates: true });
      const ws2 = wb2.Sheets[wb2.SheetNames[0]];
      const rows2 = XLSX.utils.sheet_to_json(ws2, { header: 1, raw: true, cellDates: true });
      ORDER_DATA = parseOrderRows(rows2);
    }
    const orderMsg = b64Order
      ? (ORDER_DATA.length > 0 ? ORDER_DATA.length + '건 주문' : '⚠️ 주문 0건')
      : '';
    status.textContent = '✓ 저장된 데이터 복원 (' +
      (b64Sales ? SALES_DATA.length + '개 강의' : '') +
      (b64Sales && orderMsg ? ' / ' : '') + orderMsg + ')';
    document.getElementById('upload-badge').innerHTML =
      '<span style="background:rgba(16,185,129,0.2);color:var(--green);padding:1px 8px;border-radius:4px;font-size:11px;margin-left:4px;">적용됨</span>';
    renderList();
  } catch(e) {
    status.textContent = '복원 실패: ' + e.message;
  }
})();
